using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// --- 1. GetTypeInfo<T>(): strongly-typed metadata retrieval ---
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

JsonTypeInfo<WeatherForecast> typeInfo = options.GetTypeInfo<WeatherForecast>();
Console.WriteLine($"GetTypeInfo<WeatherForecast> → Type = {typeInfo.Type.Name}");

var forecast = new WeatherForecast("Seattle", 62);
string json = JsonSerializer.Serialize(forecast, typeInfo);
Console.WriteLine($"Serialized: {json}");

// --- 2. TryGetTypeInfo<T>(): probe without throwing ---

// 2a. Type that IS resolvable (default reflection resolver handles it)
if (options.TryGetTypeInfo<WeatherForecast>(out var resolved))
    Console.WriteLine($"TryGet succeeded for {resolved!.Type.Name}");
else
    Console.WriteLine("TryGet failed for WeatherForecast (unexpected)");

// 2b. Type that is NOT resolvable — use an empty resolver so nothing resolves
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver
    {
        Modifiers = { (ti) => throw new NotSupportedException() }
    }
};

if (limited.TryGetTypeInfo<WeatherForecast>(out var maybe))
    Console.WriteLine($"TryGet succeeded (unexpected): {maybe!.Type.Name}");
else
    Console.WriteLine("TryGet correctly returned false — no metadata available");

public record WeatherForecast(string City, int TempF);

